import{j as a,b as e,c as o,aa as t}from"./chunks/framework.Bxf40uRC.js";const b=JSON.parse('{"title":"面试问题","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/面试问题.md","filePath":"计算机网络/面试问题.md","lastUpdated":null}'),l={name:"计算机网络/面试问题.md"},i=t('<h1 id="面试问题" tabindex="-1">面试问题 <a class="header-anchor" href="#面试问题" aria-label="Permalink to &quot;面试问题&quot;">​</a></h1><p><img src="https://s2.loli.net/2024/03/17/fBW4uYZk38LHUzQ.png" alt="osi七层模型2"></p><h2 id="为什么要三次握手-四次挥手" tabindex="-1">为什么要三次握手，四次挥手 <a class="header-anchor" href="#为什么要三次握手-四次挥手" aria-label="Permalink to &quot;为什么要三次握手，四次挥手&quot;">​</a></h2><h2 id="客户端挂了的话-后续流程怎么处理" tabindex="-1">客户端挂了的话，后续流程怎么处理 <a class="header-anchor" href="#客户端挂了的话-后续流程怎么处理" aria-label="Permalink to &quot;客户端挂了的话，后续流程怎么处理&quot;">​</a></h2><h2 id="tcp状态码之4xx-和5xx" tabindex="-1">tcp状态码之4xx 和5xx? <a class="header-anchor" href="#tcp状态码之4xx-和5xx" aria-label="Permalink to &quot;tcp状态码之4xx 和5xx?&quot;">​</a></h2><p>200:请求成功</p><p>201:资源已创建</p><p>202:请求已接受，但是尚未处理</p><p>301：永久重定向</p><p>302：临时重定向</p><p>304：未修改</p><p>400：请求错误</p><p>401：未认证</p><p>402：需要付费</p><p>403：禁止访问</p><p>404：页面没找到</p><p>405：请求资源方式不允许</p><p>500：服务器内部错误</p><p>501：尚未实施</p><p>502：错误网关</p><p>503：服务不可用</p><p>504：网关超时</p><h2 id="session-存在于哪里-说说cookie-和-token" tabindex="-1">session 存在于哪里？说说cookie 和 token？ <a class="header-anchor" href="#session-存在于哪里-说说cookie-和-token" aria-label="Permalink to &quot;session  存在于哪里？说说cookie 和 token？&quot;">​</a></h2><p><a href="https://sloving.top/blogs/Note/chushiJWT.html" target="_blank" rel="noreferrer">https://sloving.top/blogs/Note/chushiJWT.html</a></p><ol><li><p>session存在于服务器；session 是另一种记录服务器和客户端会话状态的机制；</p></li><li><p>cookie是服务器发送给浏览器的小块数据，里面可能包含session_id，浏览器下次再次访问服务器时，如果在一个域下，就会自动携带cookie，做一些登录校验，信息共享等功能；分为会话cookie和持久cookie；</p></li><li><p>token是一种凭证，访问对应的资源接口；一般由 user_id + time + (权限范围) + (签名)组成；一般是用户通过账号密码登录后，服务器端验证无问题生成的，返回到浏览器，存储在cookie或者localstorage中；</p></li><li><p>jwt: token的一种，header + payload + signature组成，相比token，访问服务器，验证过程，获取用户信息等过程更加方便，而且能够解决跨域，csrf攻击；</p></li></ol><h2 id="socket服务器和客户端工作流程" tabindex="-1">socket服务器和客户端工作流程 <a class="header-anchor" href="#socket服务器和客户端工作流程" aria-label="Permalink to &quot;socket服务器和客户端工作流程&quot;">​</a></h2><h3 id="服务器端的工作流程" tabindex="-1">服务器端的工作流程 <a class="header-anchor" href="#服务器端的工作流程" aria-label="Permalink to &quot;服务器端的工作流程&quot;">​</a></h3><ol><li>创建socket：服务器端会先创建一个socket，用于监听来自客户端的连接请求；</li><li>bind：服务器端将socket绑定到一个指定的网络地址和端口，从而监听来自于这个地址和端口的请求；</li><li>Listen：监听绑定地址上的请求，等待客户端的连接请求；</li><li>accept：接受连接，当一个客户端请求连接的时候，服务器端的socket接受请求并建立一个新的socket连接，专门用于与该客户端进行通信；</li><li>数据交换：一旦建立连接，服务器端就可以通过新建立的socket与客户端进行数据读写操作；</li><li>关闭连接：数据交换完成后，服务器端关闭与客户端的连接。服务器可以继续监听其他客户端的连接请求；</li></ol><h3 id="客户端的工作流程" tabindex="-1">客户端的工作流程 <a class="header-anchor" href="#客户端的工作流程" aria-label="Permalink to &quot;客户端的工作流程&quot;">​</a></h3><ol><li>创建Socket：客户端创建一个socket，用于与服务器端的socket进行连接；</li><li>connect：客户端的socket尝试连接服务器端的socket，需要指定服务器的网络地址和端口号；</li><li>数据交换；</li><li>关闭连接；</li></ol><h2 id="https的ssl握手流程" tabindex="-1">https的ssl握手流程 <a class="header-anchor" href="#https的ssl握手流程" aria-label="Permalink to &quot;https的ssl握手流程&quot;">​</a></h2><h2 id="web接口比较慢-有哪些方式进行排查" tabindex="-1">web接口比较慢，有哪些方式进行排查？ <a class="header-anchor" href="#web接口比较慢-有哪些方式进行排查" aria-label="Permalink to &quot;web接口比较慢，有哪些方式进行排查？&quot;">​</a></h2><h4 id="网络" tabindex="-1">网络 <a class="header-anchor" href="#网络" aria-label="Permalink to &quot;网络&quot;">​</a></h4><ol><li>检查网络：通过ping或者traceroute命令检查网络连接状态</li><li>资源加载：是否存在大量的前端资源加载问题</li></ol><h4 id="数据库" tabindex="-1">数据库 <a class="header-anchor" href="#数据库" aria-label="Permalink to &quot;数据库&quot;">​</a></h4><ol><li>慢查询优化：开启数据库的慢查询日志功能，分析执行时间长的SQL查询，并进行优化。</li><li>索引优化：是否对常用的key进行建立索引，或者查询是否走了索引? 采用explain命令查看详细信息</li><li>优化sql查询：比如select * 这种尽量不要存在</li></ol><h4 id="服务器配置资源" tabindex="-1">服务器配置资源 <a class="header-anchor" href="#服务器配置资源" aria-label="Permalink to &quot;服务器配置资源&quot;">​</a></h4><ol><li>CPU和内存是否过大，是否存在资源的限制，通过TOP可以查询，P是按照CPU占用率倒序，M是内存倒序</li></ol><h4 id="应用程序" tabindex="-1">应用程序 <a class="header-anchor" href="#应用程序" aria-label="Permalink to &quot;应用程序&quot;">​</a></h4><ol><li>代码程序复杂度是否过高，可以通过一些代码分析工具分析哪些代码执行时间长；</li><li>是否存在并发逻辑问题；</li></ol><h2 id="没有建立连接-客户端直接发送数据给客户端会发生什么" tabindex="-1">没有建立连接，客户端直接发送数据给客户端会发生什么？ <a class="header-anchor" href="#没有建立连接-客户端直接发送数据给客户端会发生什么" aria-label="Permalink to &quot;没有建立连接，客户端直接发送数据给客户端会发生什么？&quot;">​</a></h2><p>如果没有建立连接，客户端尝试直接发送数据给服务器通常会导致以下几种情况，具体取决于所使用的通信协议：</p><h3 id="使用tcp协议" tabindex="-1">使用TCP协议 <a class="header-anchor" href="#使用tcp协议" aria-label="Permalink to &quot;使用TCP协议&quot;">​</a></h3><p>TCP（传输控制协议）是一种面向连接的协议，要求在数据传输之前必须建立连接。如果尝试在没有建立TCP连接的情况下发送数据：</p><ul><li><strong>连接未建立</strong>：客户端无法直接发送数据包给服务器，因为TCP协议要求在数据传输前通过三次握手过程建立连接。如果客户端尝试发送数据，操作系统通常会返回一个错误，提示没有建立连接。</li><li><strong>数据丢失</strong>：即使数据包被客户端强行发送出去，由于服务器端没有与之对应的连接状态，服务器将无法正确处理这些数据包，数据包会被服务器忽略或丢弃。</li></ul><h3 id="使用udp协议" tabindex="-1">使用UDP协议 <a class="header-anchor" href="#使用udp协议" aria-label="Permalink to &quot;使用UDP协议&quot;">​</a></h3><p>UDP（用户数据报协议）是一种无连接的协议，它允许数据包（数据报）在没有预先建立连接的情况下被发送。</p><ul><li><strong>数据可能到达</strong>：使用UDP，客户端可以在没有建立连接的情况下向服务器发送数据包。因为UDP不要求建立连接，数据包有可能到达服务器。</li><li><strong>无可靠性保证</strong>：UDP不保证数据包的到达顺序、可靠性或数据完整性。发送的数据可能会丢失、重复或乱序到达，而且UDP协议本身不提供重传机制或到达确认。</li></ul>',48),s=[i];function r(h,n,c,p,d,k){return e(),o("div",null,s)}const x=a(l,[["render",r]]);export{b as __pageData,x as default};
